  // Calculate distributed shard range [start, end] distributed equally
  private calculateShardRange(filesCount: number, index: number, count: number): [number, number] {
    const baseShardSize = Math.floor(filesCount / count)
    const remainderTestFilesCount = filesCount % count
    if (remainderTestFilesCount >= index) {
      const shardSize = baseShardSize + 1
      const shardStart = shardSize * (index - 1)
      const shardEnd = shardSize * index
      return [shardStart, shardEnd]
    }

    const shardStart = remainderTestFilesCount * (baseShardSize + 1) + (index - remainderTestFilesCount - 1) * baseShardSize
    const shardEnd = shardStart + baseShardSize
    return [shardStart, shardEnd]
  }

  private sorted<T extends { path: string; duration: number }>(entries: T[]): T[] {
    return [...entries].sort((a, b) => b.duration - a.duration || a.path.localeCompare(b.path))
  }

  private lpt<T extends { path: string; duration: number }>(entries: T[], count: number, shards = Array.from({ length: count }, () => [] as T[])): T[][] {
    const loads = shards.map(shard => shard.reduce((sum, entry) => sum + entry.duration, 0))
    for (const entry of this.sorted(entries)) {
      const target = loads.reduce((best, load, i) => load < loads[best] ? i : best, 0)
      shards[target].push(entry)
      loads[target] += entry.duration
    }
    return shards
  }

  private roundRobin<T extends { path: string; duration: number }>(entries: T[], count: number): T[][] {
    const shards = Array.from({ length: count }, () => [] as T[])
    let shard = 0
    let direction = 1
    for (const entry of this.sorted(entries)) {
      shards[shard].push(entry)
      shard += direction
      if (shard >= count) {
        shard = count - 1
        direction = -1
      }
      else if (shard < 0) {
        shard = 0
        direction = 1
      }
    }
    return shards
  }

  private affinity<T extends { path: string; duration: number }>(entries: T[], count: number): T[][] {
    const shards = Array.from({ length: count }, () => [] as T[])
    const unmatched: T[] = []
    for (const entry of entries) {
      const shard = getAffinityShard(entry.path, this.ctx.config.sequence.shardAffinityRules, count)
      if (shard === undefined) {
        unmatched.push(entry)
      }
      else { shards[shard].push(entry) }
    }
    return unmatched.length === entries.length ? this.lpt(entries, count) : this.lpt(unmatched, count, shards)
  }

  private isolateSlow<T extends { path: string; duration: number }>(entries: T[], count: number, threshold: number): T[][] {
    const slow = this.sorted(entries.filter(entry => entry.duration > threshold))
    const remaining = entries.filter(entry => entry.duration <= threshold)
    const shards = Array.from({ length: count }, () => [] as T[])
    if (slow.length >= count) {
      slow.slice(0, count - 1).forEach((entry, i) => shards[i].push(entry))
      shards[count - 1].push(...slow.slice(count - 1), ...remaining)
      return shards
    }
    slow.forEach((entry, i) => shards[i].push(entry))
    return this.lpt(remaining, count, shards)
  }
